import{_ as a,c as t,o as s,a1 as l}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Install Agent Skills: Quick Setup | Agent Skills","description":"Learn to install Agent Skills to Claude Code and claude.ai. Master npx quick installation, manual skill copy, and network permission configuration. Resolve common issues like inactive skills and deployment errors.","frontmatter":{"title":"Install Agent Skills: Quick Setup | Agent Skills","sidebarTitle":"Install","subtitle":"Install Agent Skills: Quick Setup","description":"Learn to install Agent Skills to Claude Code and claude.ai. Master npx quick installation, manual skill copy, and network permission configuration. Resolve common issues like inactive skills and deployment errors.","tags":["Installation","Claude Code","claude.ai","Network Permissions"],"order":20,"prerequisite":["start-getting-started"]},"headers":[],"relativePath":"vercel-labs/agent-skills/start/installation/index.md","filePath":"vercel-labs/agent-skills/start/installation/index.md"}'),i={name:"vercel-labs/agent-skills/start/installation/index.md"};function o(n,e,r,d,c,p){return s(),t("div",null,[...e[0]||(e[0]=[l(`<h1 id="install-agent-skills" tabindex="-1">Install Agent Skills <a class="header-anchor" href="#install-agent-skills" aria-label="Permalink to &quot;Install Agent Skills&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Quick install Agent Skills with one command (recommended)</li><li>Manually copy skills to Claude Code&#39;s local directory</li><li>Enable skills in claude.ai and configure network permissions</li><li>Troubleshoot common installation errors</li></ul><h2 id="your-current-situation" tabindex="-1">Your Current Situation <a class="header-anchor" href="#your-current-situation" aria-label="Permalink to &quot;Your Current Situation&quot;">​</a></h2><p>You want to use Agent Skills to have Claude help you deploy projects and review code, but you don&#39;t know how to install them to Claude Code or claude.ai. Or you&#39;ve tried installing, but the skills aren&#39;t activated, and you&#39;re getting &quot;Network Egress Error&quot; when deploying.</p><h2 id="when-to-use-this" tabindex="-1">When to Use This <a class="header-anchor" href="#when-to-use-this" aria-label="Permalink to &quot;When to Use This&quot;">​</a></h2><ul><li>✓ First time using Agent Skills</li><li>✓ You use Claude Code (terminal command-line tool)</li><li>✓ You use claude.ai (web version of Claude)</li><li>✓ You need skills to access the network (deployment features)</li></ul><h2 id="🎒-prerequisites" tabindex="-1">🎒 Prerequisites <a class="header-anchor" href="#🎒-prerequisites" aria-label="Permalink to &quot;🎒 Prerequisites&quot;">​</a></h2><p>Before starting, make sure you have:</p><ul><li>[ ] Node.js 20+ installed</li><li>[ ] An active Claude Code or claude.ai account</li></ul><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>If you haven&#39;t learned what Agent Skills is yet, I recommend reading <a href="./../getting-started/">Getting Started with Agent Skills</a> first.</p></div><h2 id="core-approach" tabindex="-1">Core Approach <a class="header-anchor" href="#core-approach" aria-label="Permalink to &quot;Core Approach&quot;">​</a></h2><p>There are two ways to install Agent Skills:</p><ol><li><strong>npx installation (recommended)</strong>: One-click install to Claude Code, automatically completes all steps</li><li><strong>Manual installation</strong>: Copy files to a specified directory, suitable for claude.ai or custom installation locations</li></ol><p>After installation, skills will automatically activate in Claude—simply trigger a keyword (like &quot;Deploy my app&quot;), and Claude will automatically call the corresponding skill.</p><h2 id="method-1-npx-quick-installation-recommended" tabindex="-1">Method 1: npx Quick Installation (Recommended) <a class="header-anchor" href="#method-1-npx-quick-installation-recommended" aria-label="Permalink to &quot;Method 1: npx Quick Installation (Recommended)&quot;">​</a></h2><p>This is the simplest installation method, suitable for Claude Code users.</p><h3 id="step-1-run-the-installation-command" tabindex="-1">Step 1: Run the Installation Command <a class="header-anchor" href="#step-1-run-the-installation-command" aria-label="Permalink to &quot;Step 1: Run the Installation Command&quot;">​</a></h3><p>Execute in your terminal:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add-skill</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vercel-labs/agent-skills</span></span></code></pre></div><p><strong>Why</strong><code>add-skill</code> is an npm package that automatically downloads Agent Skills and installs them to the correct directory.</p><p><strong>You should see</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Skills successfully installed.</span></span></code></pre></div><h3 id="step-2-verify-installation" tabindex="-1">Step 2: Verify Installation <a class="header-anchor" href="#step-2-verify-installation" aria-label="Permalink to &quot;Step 2: Verify Installation&quot;">​</a></h3><p>In Claude Code, enter:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>List available skills</span></span></code></pre></div><p><strong>You should see</strong>: The skill list returned by Claude includes:</p><ul><li><code>react-best-practices</code></li><li><code>web-design-guidelines</code></li><li><code>vercel-deploy</code></li></ul><p><strong>Checkpoint ✅</strong>: If you see these 3 skills, installation was successful.</p><h2 id="method-2-manual-installation-to-claude-code" tabindex="-1">Method 2: Manual Installation to Claude Code <a class="header-anchor" href="#method-2-manual-installation-to-claude-code" aria-label="Permalink to &quot;Method 2: Manual Installation to Claude Code&quot;">​</a></h2><p>If you don&#39;t want to use npx, or need to control the installation location, use manual installation.</p><h3 id="step-1-clone-or-download-the-project" tabindex="-1">Step 1: Clone or Download the Project <a class="header-anchor" href="#step-1-clone-or-download-the-project" aria-label="Permalink to &quot;Step 1: Clone or Download the Project&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/vercel-labs/agent-skills.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agent-skills</span></span></code></pre></div><p><strong>Why</strong> Manual installation requires obtaining the project source code first.</p><h3 id="step-2-copy-skills-to-claude-code-directory" tabindex="-1">Step 2: Copy Skills to Claude Code Directory <a class="header-anchor" href="#step-2-copy-skills-to-claude-code-directory" aria-label="Permalink to &quot;Step 2: Copy Skills to Claude Code Directory&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills/react-best-practices</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.claude/skills/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills/web-design-guidelines</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.claude/skills/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills/claude.ai/vercel-deploy-claimable</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.claude/skills/vercel-deploy</span></span></code></pre></div><p><strong>Why</strong> Claude Code stores skills in the <code>~/.claude/skills/</code> directory. After copying, Claude can recognize these skills.</p><p><strong>You should see</strong>: No error output after command execution.</p><p><strong>Checkpoint ✅</strong>: Use <code>ls ~/.claude/skills/</code> to verify, you should see 3 skill directories: <code>react-best-practices</code>, <code>web-design-guidelines</code>, <code>vercel-deploy</code>.</p><h3 id="step-3-restart-claude-code" tabindex="-1">Step 3: Restart Claude Code <a class="header-anchor" href="#step-3-restart-claude-code" aria-label="Permalink to &quot;Step 3: Restart Claude Code&quot;">​</a></h3><p>Force quit Claude Code, then reopen it.</p><p><strong>Why</strong> Claude Code only loads the skill list at startup—you need to restart to recognize newly installed skills.</p><h2 id="method-3-using-skills-in-claude-ai" tabindex="-1">Method 3: Using Skills in claude.ai <a class="header-anchor" href="#method-3-using-skills-in-claude-ai" aria-label="Permalink to &quot;Method 3: Using Skills in claude.ai&quot;">​</a></h2><p>If you use claude.ai (the web version of Claude), the installation method is different.</p><h3 id="method-3-1-add-to-project-knowledge-base" tabindex="-1">Method 3.1: Add to Project Knowledge Base <a class="header-anchor" href="#method-3-1-add-to-project-knowledge-base" aria-label="Permalink to &quot;Method 3.1: Add to Project Knowledge Base&quot;">​</a></h3><h4 id="step-1-select-skill-files" tabindex="-1">Step 1: Select Skill Files <a class="header-anchor" href="#step-1-select-skill-files" aria-label="Permalink to &quot;Step 1: Select Skill Files&quot;">​</a></h4><p>Package all files from the <code>skills/react-best-practices</code>, <code>skills/web-design-guidelines</code>, and <code>skills/claude.ai/vercel-deploy-claimable</code> directories.</p><p><strong>Why</strong> claude.ai requires adding skill files as a &quot;knowledge base&quot; to your project.</p><h4 id="step-2-upload-to-project" tabindex="-1">Step 2: Upload to Project <a class="header-anchor" href="#step-2-upload-to-project" aria-label="Permalink to &quot;Step 2: Upload to Project&quot;">​</a></h4><p>In claude.ai:</p><ol><li>Create or open a project</li><li>Click &quot;Knowledge&quot; → &quot;Add Files&quot;</li><li>Upload skill files (or the entire directory)</li></ol><p><strong>You should see</strong>: The project&#39;s file list is displayed in the knowledge base.</p><h3 id="method-3-2-paste-skill-md-content" tabindex="-1">Method 3.2: Paste SKILL.md Content <a class="header-anchor" href="#method-3-2-paste-skill-md-content" aria-label="Permalink to &quot;Method 3.2: Paste SKILL.md Content&quot;">​</a></h3><p>If you don&#39;t want to upload the entire directory, you can directly copy the contents of <code>SKILL.md</code>.</p><h4 id="step-1-copy-skill-definition" tabindex="-1">Step 1: Copy Skill Definition <a class="header-anchor" href="#step-1-copy-skill-definition" aria-label="Permalink to &quot;Step 1: Copy Skill Definition&quot;">​</a></h4><p>Open <code>skills/react-best-practices/SKILL.md</code> and copy all contents.</p><p><strong>Why</strong><code>SKILL.md</code> contains the complete skill definition. Claude will understand the skill&#39;s functionality based on this file.</p><h4 id="step-2-paste-into-conversation" tabindex="-1">Step 2: Paste into Conversation <a class="header-anchor" href="#step-2-paste-into-conversation" aria-label="Permalink to &quot;Step 2: Paste into Conversation&quot;">​</a></h4><p>Paste the <code>SKILL.md</code> contents into a claude.ai conversation, or add it to the project&#39;s &quot;Instructions&quot;.</p><p><strong>You should see</strong>: Claude confirms receiving the skill definition.</p><h2 id="configure-network-permissions-important" tabindex="-1">Configure Network Permissions (Important) <a class="header-anchor" href="#configure-network-permissions-important" aria-label="Permalink to &quot;Configure Network Permissions (Important)&quot;">​</a></h2><p>If you use the <code>vercel-deploy</code> skill to deploy projects, you need to configure network permissions.</p><div class="warning custom-block"><p class="custom-block-title">Important</p><p>The <code>vercel-deploy</code> skill needs access to <code>*.vercel.com</code> domains to upload deployments. Skipping this step will cause deployment failures!</p></div><h3 id="step-1-open-claude-capabilities-settings" tabindex="-1">Step 1: Open Claude Capabilities Settings <a class="header-anchor" href="#step-1-open-claude-capabilities-settings" aria-label="Permalink to &quot;Step 1: Open Claude Capabilities Settings&quot;">​</a></h3><p>Visit in your browser:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://claude.ai/settings/capabilities</span></span></code></pre></div><p><strong>Why</strong> This controls the list of domains Claude can access.</p><h3 id="step-2-add-vercel-domain" tabindex="-1">Step 2: Add Vercel Domain <a class="header-anchor" href="#step-2-add-vercel-domain" aria-label="Permalink to &quot;Step 2: Add Vercel Domain&quot;">​</a></h3><p>Click &quot;Add domain&quot; and enter:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>*.vercel.com</span></span></code></pre></div><p>Click &quot;Save&quot; to save.</p><p><strong>You should see</strong>: <code>*.vercel.com</code> appears in the domain list.</p><p><strong>Checkpoint ✅</strong>: Domain added—skills can now access the network.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="problem-1-skills-not-activated" tabindex="-1">Problem 1: Skills Not Activated <a class="header-anchor" href="#problem-1-skills-not-activated" aria-label="Permalink to &quot;Problem 1: Skills Not Activated&quot;">​</a></h3><p><strong>Symptom</strong>: You enter &quot;Deploy my app&quot;, but Claude doesn&#39;t know what to do.</p><p><strong>Possible causes</strong>:</p><ul><li>Claude Code not restarted (for manual installation)</li><li>claude.ai project knowledge base didn&#39;t correctly load skills</li></ul><p><strong>Solutions</strong>:</p><ul><li>Claude Code: Restart the app</li><li>claude.ai: Confirm skill files have been uploaded to the project&#39;s Knowledge</li></ul><h3 id="problem-2-deployment-failed-network-egress-error" tabindex="-1">Problem 2: Deployment Failed (Network Egress Error) <a class="header-anchor" href="#problem-2-deployment-failed-network-egress-error" aria-label="Permalink to &quot;Problem 2: Deployment Failed (Network Egress Error)&quot;">​</a></h3><p><strong>Symptom</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Deployment failed due to network restrictions</span></span></code></pre></div><p><strong>Solution</strong>: Check if <code>*.vercel.com</code> has been added to network permissions:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Visit https://claude.ai/settings/capabilities</span></span>
<span class="line"><span>Check if *.vercel.com is included</span></span></code></pre></div><h3 id="problem-3-can-t-find-claude-skills-directory" tabindex="-1">Problem 3: Can&#39;t Find <code>~/.claude/skills/</code> Directory <a class="header-anchor" href="#problem-3-can-t-find-claude-skills-directory" aria-label="Permalink to &quot;Problem 3: Can&#39;t Find \`~/.claude/skills/\` Directory&quot;">​</a></h3><p><strong>Symptom</strong>: During manual installation, you&#39;re told the directory doesn&#39;t exist.</p><p><strong>Solution</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.claude/skills/</span></span></code></pre></div><h3 id="problem-4-npx-installation-failed" tabindex="-1">Problem 4: npx Installation Failed <a class="header-anchor" href="#problem-4-npx-installation-failed" aria-label="Permalink to &quot;Problem 4: npx Installation Failed&quot;">​</a></h3><p><strong>Symptom</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npx: command not found</span></span></code></pre></div><p><strong>Solution</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Confirm Node.js and npm are installed</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># If not installed, install the LTS version from https://nodejs.org/</span></span></code></pre></div><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>This lesson introduced three methods to install Agent Skills:</p><ul><li><strong>npx quick installation</strong>: Recommended for Claude Code, one-click completion</li><li><strong>Manual installation</strong>: Copy files to <code>~/.claude/skills/</code>, suitable for controlling installation location</li><li><strong>claude.ai installation</strong>: Upload files to project knowledge base or paste <code>SKILL.md</code></li></ul><p>If you use the <code>vercel-deploy</code> skill, don&#39;t forget to add <code>*.vercel.com</code> network permissions at <code>https://claude.ai/settings/capabilities</code>.</p><p>After installation, you can have Claude automatically use these skills for code review, accessibility checks, and project deployment.</p><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../../platforms/react-best-practices/">React/Next.js Performance Optimization Best Practices</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>How to use 57 React performance optimization rules</li><li>Eliminate waterfalls, optimize bundle size, reduce re-renders</li><li>Have AI automatically review code and provide fix suggestions</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-25</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line #</th></tr></thead><tbody><tr><td>npx installation method</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/README.md#L83-L86" target="_blank" rel="noreferrer"><code>README.md:83-86</code></a></td><td>83-86</td></tr><tr><td>Claude Code manual installation</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L98-L105" target="_blank" rel="noreferrer"><code>AGENTS.md:98-105</code></a></td><td>98-105</td></tr><tr><td>claude.ai installation method</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L106-L109" target="_blank" rel="noreferrer"><code>AGENTS.md:106-109</code></a></td><td>106-109</td></tr><tr><td>Network permission configuration</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/skills/claude.ai/vercel-deploy-claimable/SKILL.md#L104-L112" target="_blank" rel="noreferrer"><code>skills/claude.ai/vercel-deploy-claimable/SKILL.md:104-112</code></a></td><td>104-112</td></tr></tbody></table><p><strong>Key Skill Packages</strong>:</p><ul><li><code>react-best-practices</code>: 57 React performance optimization rules</li><li><code>web-design-guidelines</code>: 100+ web design guideline rules</li><li><code>vercel-deploy</code>: One-click deployment to Vercel (supports 40+ frameworks)</li></ul></details>`,104)])])}const k=a(i,[["render",o]]);export{u as __pageData,k as default};
